import numpy as np
import numpy.ma as ma
import glob
import matplotlib.pyplot as plt
import os
import scipy.io
import xarray as xr
import xcdat
from datetime import datetime
from dateutil.relativedelta import relativedelta

# Convective onset metrics generated by the Neelin group, UCLA
# Original code: Kathleen Schiro, python version 22 Dec 2016, references provided in detail from convective_onset_statistics_ARM_Diagnostics.py

from .convection_onset_statistics import convection_onset_statistics
from .dataset import open_dataset

def convection_onset(parameter):
    """Calculate """
    variables = parameter.variables
    #seasons = parameter.season
    test_path = parameter.test_data_path
    obs_path = parameter.obs_path
    cmip_path = parameter.cmip_path
    output_path = parameter.output_path
    sites = parameter.sites
    
   
    test_model = parameter.test_data_set 
 
    arm_name = parameter.arm_filename
    #ref_models = parameter.ref_models

    print('============================================================')
    print('Create Convection Onset Metrics: '+sites[0])
    print('============================================================')
    
    #Read in observation data
    precip_threshold = 0.5
    #print('Read in observation data')
    for index, site in enumerate(sites):
        #print('site',site)
        #print('index',index)
        if site == 'twpc1':     #twpc1
            cwv_max = 85
            cwv_min = 28
            bin_width = 1.5
            sitename = 'Manus Island'
        if site == 'twpc2':     #twpc2
            cwv_max = 70
            cwv_min = 28
            bin_width = 2.0
            sitename = 'Nauru'
        if site == 'twpc3':     #twpc3
            cwv_max = 85
            cwv_min = 28
            bin_width = 2.0
            sitename = 'Darwin'
        if site == 'sgpc1':     #sgp
            cwv_max = 75
            cwv_min = 20
            bin_width = 2.0
            sitename = 'SGP'
        if site == 'nsac1':     #nsa
            cwv_max = 50
            cwv_min = 20
            bin_width = 2.0
            sitename = 'NSA'
        if site == 'enac1':     #ena
            cwv_max = 75
            cwv_min = 20
            bin_width = 2.0
            sitename = 'ENA'
        if site == 'maom1':     #mao
            cwv_max = 85
            cwv_min = 20
            bin_width = 2.0
            sitename = 'Manacapuru'
    
        # Generate new folder given site names [XZ]
        if not os.path.exists(os.path.join(output_path,'figures',site)):
            os.makedirs(os.path.join(output_path,'figures',site)) 
        output_path_co = os.path.join(output_path,'figures',site)

        for va in variables:
            #print(glob.glob(os.path.join(obs_path,'ARMdiag_'+va+'_1hr_*_'+site+'.nc')))
            
            if not arm_name:
                filename = glob.glob(os.path.join(obs_path,'ARMdiag_'+va+'_1hr_*_'+site+'.nc'))[0]
            else:
                filename = glob.glob(os.path.join(obs_path,site[:3]+'armdiags1hr' + site[3:5].upper()+'*.nc'))[0]
            
            print('filename: ',filename)
            
            # Open dataset with xarray
            obs_dataset = open_dataset(filename, name="OBS")
            
            # Get variable from dataset
            var = obs_dataset.get_variable(va)
            print('var_shape: ',va, var.shape)
            
            # Convert to numpy array for processing
            var_data = var.values
            
            if va == 'pr':
                precip = var_data
                precip[precip < -900] = np.nan
                #print('Max PRECIP:', np.nanmax(precip))
            if va == 'prw':
                prw = var_data
                prw[prw < -900] = np.nan
                #print('Max PRW:', np.nanmax(prw))
        convection_onset_statistics(precip_threshold,cwv_max,cwv_min,bin_width,prw, precip,'ARM',output_path_co,sites,sitename)
       
        #Process model results
        print('Start model')
        pr_mod_index = 0
        pr_prw_mod = []
        for va in variables:
            
            if not arm_name:
                filename = glob.glob(os.path.join(test_path, '*'+va+'_cfSites_'+test_model+'*'+site+'.nc'))
            else:
                test_model = ''.join(e for e in test_model if e.isalnum()).lower()
                print(va,':',test_model,test_path)
                filename = glob.glob(os.path.join(test_path,site[:3]+test_model+'subday' + site[3:5].upper()+'*.nc' ))
            print(filename)
            if len(filename) == 0:
               print(va,':','No sub daily data for test model were found.')
            else:
                pr_mod_index = 1
                
                # Open dataset with xarray
                model_dataset = open_dataset(filename[0], name=test_model)
                
                # Get variable from dataset
                var = model_dataset.get_variable(va)
                
                # Convert to numpy array for processing
                var_data = var.values
                
                if va == 'pr':
                    var_data = var_data * 3600.  # 'kg m-2 s-1' to 'mm/hr'
                
                pr_prw_mod.append(var_data)
        if pr_mod_index == 1:
             convection_onset_statistics(precip_threshold,cwv_max,cwv_min,bin_width,pr_prw_mod[1],pr_prw_mod[0],test_model,output_path_co,sites,sitename)
 
